//! GoodOS 内核二进制 crate —— 架构入口、内嵌用户程序、模块组装。

#![no_std]
#![no_main]
#![allow(dead_code)]
#![allow(warnings)]

use core::arch::global_asm;
use task;

#[cfg(target_arch = "riscv64")]
global_asm!(
    r#"
    .section .text.entry
    .globl _start
_start:
    bnez a0, _secondary_hart_park
    .option push
    .option norelax
    la   gp, __global_pointer$
    .option pop
    lla  sp, boot_stack_top
    mv   a0, a1
    call rust_main

_secondary_hart_park:
    wfi
    j _secondary_hart_park

    .section .boot_stack, "aw", @nobits
    .align 12
boot_stack:
    .space 262144
boot_stack_top:
"#
);

#[cfg(target_arch = "loongarch64")]
global_asm!(
    r#"
    .section .text.entry
    .globl _start
_start:
    la.local $sp, boot_stack_top
    or       $r4, $r5, $r0
    bl       rust_main
1:
    idle     0
    b        1b

    .section .bss.boot_stack
    .align 12
boot_stack:
    .space 262144
boot_stack_top:
"#
);

// 内嵌用户程序：build.rs 生成 incbin 汇编 + Rust 元数据，由 init_proc 消费。
global_asm!(include_str!(concat!(env!("OUT_DIR"), "/link_apps.S")));

pub mod log;
pub mod entry;
pub mod init;
pub mod panic;
pub mod init_proc;
pub mod trap_handler;

/// 内核上下文切换汇编（__switch）：调度器须保证传入的 kernel stack 在切换过程中有效。
extern "C" {
    pub fn __switch(current: *mut task::KernelContext, target: *const task::KernelContext);
}

/// boot/idle 上下文。
pub static mut BOOT_CTX: task::KernelContext = task::KernelContext::zeroed();
pub static mut INIT_DUMMY: task::KernelContext = task::KernelContext::zeroed();

// 调度器运行循环，核心初始化流程在 entry.rs。

use crate::log;
use task;

/// 进入调度器循环，永不返回。
pub fn run() -> ! {
    loop {
        match task::fetch_next_task() {
            Some(tcb) => {
                task::run_task(&tcb);
            }
            None => {
                core::hint::spin_loop();
            }
        }
    }
}

// 内核入口：boot CPU 初始化 → 创建 init 任务 → 轮询调度器 → 关机。

use crate::log;
use hal::{Arch, ArchBoot, ArchTrap};
use driver;
use mm;
use task;
use fs;

/// 汇编桩之后的 Rust 入口。dtb_addr 在分页和分配器初始化之前保存。
#[no_mangle]
pub extern "C" fn rust_main(dtb_addr: usize) -> ! {
    _boot_hart_init(dtb_addr);
    spawn_init_task();
    crate::trap_handler::start_timer();

    loop {
        if task::is_shutdown() {
            break;
        }
        task::sched_run_once();
    }

    shutdown()
}

/// 刷新 EXT4 脏数据后走平台关机原语，永不返回。
fn shutdown() -> ! {
    fs::init::mount_table().for_each_ext4(|_, ext4fs| {
        let _ = ext4fs.flush_writeback();
    });
    log::puts("\n[goodos] all done, shutting down\n");
    #[cfg(target_arch = "riscv64")]
    unsafe {
        core::arch::asm!("csrw satp, zero");
    }
    hal::Arch::shutdown()
}

/// 全局子系统初始化（boot hart）。顺序有严格依赖：
/// DTB → 架构 init → 内存 → trap → 任务 → 驱动 → 文件系统。
fn _boot_hart_init(dtb_addr: usize) {
    driver::probe::device_tree::save_dtb_addr(dtb_addr);
    hal::Arch::arch_init();
    log::init();
    log::puts("[boot] goodos kernel start: ");
    log::puts(<Arch as hal::ArchInfo>::name());
    log::puts("\n");
    #[cfg(target_arch = "loongarch64")]
    {
        extern "C" {
            fn __tlb_refill_entry();
        }
        hal::Arch::set_tlb_refill_vector(__tlb_refill_entry as usize);
    }
    mm::init(dtb_addr);
    crate::trap_handler::init();
    task::init();
    driver::manager::init(0);
    fs::init::fs_init();
}

/// 为 init_main 分配内核栈并注册为就绪任务。
/// 调度器条目 0 保留给 idle，后续用户 PID 从 1 开始。
fn spawn_init_task() {
    let npages = 64;
    let base = mm::alloc_pages_contiguous(npages).unwrap().0 * platform::PAGE_SIZE;
    let init_stack_top = base + npages * platform::PAGE_SIZE;
    #[cfg(target_arch = "loongarch64")]
    let (init_sp, init_ra) = (
        mm::phys_to_virt(init_stack_top),
        mm::phys_to_virt(init_main as usize),
    );
    #[cfg(not(target_arch = "loongarch64"))]
    let (init_sp, init_ra) = (init_stack_top, init_main as usize);

    let init_ctx = task::KernelContext {
        sp: init_sp,
        ra: init_ra,
        s0: 0, s1: 0, s2: 0, s3: 0, s4: 0, s5: 0, s6: 0, s7: 0,
        s8: 0, s9: 0, s10: 0, s11: 0,
    };

    task::sched_init(0, task::KernelContext::zeroed());
    task::sched_mark_idle(0);
    task::sched_add(0, init_ctx, 0);
}

/// 首个内核任务：优先 user_init，不可用时 fallback 到其他内嵌程序。
extern "C" fn init_main() -> ! {
    if let Some(tc) = crate::init_proc::find_testcase("user_init") {
        if tc.elf_data.len() > 1024 {
            log::puts("[init] spawning embedded user_init\n");
            let pid = crate::init_proc::spawn_embedded(&tc);
            if pid != 0 {
                task::run_process(pid);
                log::puts("[init] user_init finished\n");
                task::signal_shutdown();
                shutdown();
            }
        }
        log::puts("[init] user_init spawn failed, falling back\n");
    }

    let (list, count) = crate::init_proc::testcase_list();
    for i in 0..count {
        if let Some(ref tc) = list[i] {
            if tc.elf_data.len() > 1024 {
                let pid = crate::init_proc::spawn_embedded(tc);
                if pid != 0 {
                    task::run_process(pid);
                }
            }
        }
    }

    log::puts("[init] all done\n");
    task::signal_shutdown();
    shutdown();
}

// Trap 分发器：时钟、系统调用、缺页。HAL 解码后回调本模块进行子系统分发。

use crate::log;
use hal::{Arch, ArchBoot, ArchInt, ArchTime, ArchTrap, ArchTrapContext, TrapCause};
use mm;
use syscall;
use task;

const TIMER_TICK_NANOS: u64 = 10_000_000;

const RISCV_SCAUSE_INTERRUPT: usize = 1usize << (usize::BITS as usize - 1);
const RISCV_SCAUSE_USER_ECALL: usize = 8;
const RISCV_SCAUSE_SUPERVISOR_ECALL: usize = 9;
const RISCV_SCAUSE_SUPERVISOR_TIMER: usize = 5;
const RISCV_SCAUSE_ILLEGAL_INSTRUCTION: usize = 2;
const RISCV_SCAUSE_BREAKPOINT: usize = 3;
const RISCV_SCAUSE_INST_PAGE_FAULT: usize = 12;
const RISCV_SCAUSE_LOAD_PAGE_FAULT: usize = 13;
const RISCV_SCAUSE_STORE_PAGE_FAULT: usize = 15;

/// 注册 trap 向量和内核回调。
pub fn init() {
    #[cfg(target_arch = "riscv64")]
    {
        extern "C" { fn __trap_entry(); }
        hal::Arch::set_trap_vector(__trap_entry as usize);
    }

    #[cfg(target_arch = "loongarch64")]
    {
        extern "C" { fn __trap_entry(); }
        hal::Arch::set_trap_vector((__trap_entry as usize) | 0x9000_0000_0000_0000usize);
    }

    #[cfg(target_arch = "loongarch64")]
    {
        extern "C" { fn __tlb_refill_entry(); }
        hal::Arch::set_tlb_refill_vector(__tlb_refill_entry as usize);
    }

    hal::Arch::set_kernel_trap_handler(kernel_trap_handler);
}

#[cfg(target_arch = "riscv64")]
#[no_mangle]
pub extern "C" fn kernel_trap_dispatch(
    cx: &mut hal::TrapContext,
    scause: usize,
    stval: usize,
) {
    let cause = scause & !RISCV_SCAUSE_INTERRUPT;
    let trap = if scause & RISCV_SCAUSE_INTERRUPT != 0 {
        match cause {
            RISCV_SCAUSE_SUPERVISOR_TIMER => TrapCause::SupervisorTimer,
            _ => TrapCause::Unknown(scause),
        }
    } else {
        match cause {
            RISCV_SCAUSE_USER_ECALL => TrapCause::UserEcallsyscall(cx.regs[17]),
            RISCV_SCAUSE_SUPERVISOR_ECALL => TrapCause::SupervisorEcallsyscall(cx.regs[17]),
            RISCV_SCAUSE_ILLEGAL_INSTRUCTION => TrapCause::IllegalInstruction {
                scause,
                stval,
            },
            RISCV_SCAUSE_BREAKPOINT => TrapCause::Breakpoint,
            RISCV_SCAUSE_INST_PAGE_FAULT
            | RISCV_SCAUSE_LOAD_PAGE_FAULT
            | RISCV_SCAUSE_STORE_PAGE_FAULT => TrapCause::PageFault {
                vaddr: stval,
                flags: cause,
            },
            _ => TrapCause::Unknown(scause),
        }
    };
    kernel_trap_handler(cx, trap);
}

/// 启动周期性时钟中断（~10ms）。
pub fn start_timer() {
    let now_ticks = hal::Arch::current_ticks();
    let next_tick_nanos = hal::Arch::ticks_to_nanos(now_ticks)
        .saturating_add(TIMER_TICK_NANOS);
    hal::Arch::set_timer(next_tick_nanos);
    hal::Arch::enable_timer();
}

fn next_periodic_tick(now_ticks: u64) -> u64 {
    let now_nanos = hal::Arch::ticks_to_nanos(now_ticks);
    let one_tick_nanos = hal::Arch::ticks_to_nanos(now_ticks.saturating_add(1))
        .saturating_sub(now_nanos)
        .max(1);
    now_ticks.saturating_add(TIMER_TICK_NANOS / one_tick_nanos)
}

/// 重设时钟，取 tick / sleep / itimer 三者的最早到期时间。
fn rearm_timer(now_ticks: u64) {
    let tick_deadline = next_periodic_tick(now_ticks);
    let next_deadline = task::sleep_next_deadline()
        .into_iter()
        .chain(syscall::imp::signal::next_itimer_deadline())
        .fold(tick_deadline, |next, deadline| next.min(deadline));
    hal::Arch::set_timer(hal::Arch::ticks_to_nanos(next_deadline));
}

fn user_return_work(cx: &mut <hal::Arch as hal::ArchTrap>::Context) {
    syscall::imp::signal::check_itimers();
    task::sched_maybe_yield();
    syscall::imp::signal::deliver_pending(cx);
}

#[inline(always)]
fn user_return_work_if_needed(cx: &mut <hal::Arch as hal::ArchTrap>::Context) {
    if syscall::imp::signal::has_user_return_work() || task::has_reschedule_request() {
        user_return_work(cx);
    }
}

/// 简单 syscall 快速通道（getpid/getuid 等高频调用，跳过完整分发开销）。
#[inline(always)]
fn fast_simple_syscall(num: usize) -> Option<isize> {
    match num {
        syscall::consts::SYS_GETPID => Some(syscall::imp::task::sys_getpid()),
        syscall::consts::SYS_GETPPID => Some(syscall::imp::task::sys_getppid()),
        syscall::consts::SYS_GETUID => Some(syscall::imp::task::sys_getuid()),
        syscall::consts::SYS_GETEUID => Some(syscall::imp::task::sys_geteuid()),
        syscall::consts::SYS_GETGID => Some(syscall::imp::task::sys_getgid()),
        syscall::consts::SYS_GETEGID => Some(syscall::imp::task::sys_getegid()),
        syscall::consts::SYS_GETTID => Some(syscall::imp::task::sys_gettid()),
        _ => None,
    }
}

/// 内核 trap 回调：SupervisorTimer / UserEcallsyscall / PageFault 三类分发。
/// 缺页按 COW → lazy mmap → SIGSEGV 级联尝试。
fn kernel_trap_handler(cx: &mut <hal::Arch as hal::ArchTrap>::Context, cause: TrapCause) {
    #[cfg(target_arch = "riscv64")]
    let from_user = cx.sstatus & (1 << 8) == 0;
    #[cfg(target_arch = "loongarch64")]
    let from_user = cx.prmd & 0x3 == 0x3;

    if from_user {
        task::sched_time_trap_in();
    }

    match cause {
        TrapCause::SupervisorTimer => {
            #[cfg(target_arch = "riscv64")]
            let from_user = cx.sstatus & (1 << 8) == 0;
            #[cfg(target_arch = "loongarch64")]
            let from_user = cx.prmd & 0x3 == 0x3;

            let now_ticks = hal::Arch::current_ticks();
            if !from_user {
                task::sleep_wake_expired(now_ticks);
                syscall::imp::signal::check_itimers();
                rearm_timer(now_ticks);
                return;
            }
            task::sleep_wake_expired(now_ticks);
            syscall::imp::signal::check_itimers();
            rearm_timer(now_ticks);
            syscall::imp::signal::deliver_pending_from_timer(cx);
            task::request_reschedule();
            task::sched_maybe_yield();
        }
        TrapCause::UserEcallsyscall(num) => {
            cx.advance_pc();
            if num == syscall::consts::SYS_SIGRETURN {
                let _ = syscall::imp::signal::sys_sigreturn(cx);
                user_return_work(cx);
                if from_user {
                    task::sched_time_trap_out();
                }
                return;
            }
            if let Some(ret) = fast_simple_syscall(num) {
                cx.set_syscall_ret(ret);
                user_return_work_if_needed(cx);
                if from_user {
                    task::sched_time_trap_out();
                }
                return;
            }
            let args = cx.get_syscall_args();
            let ret = if num == syscall::consts::SYS_TIMES {
                syscall::imp::task::sys_times(args[0])
            } else {
                syscall::handle_syscall(num, args)
            };
            cx.set_syscall_ret(ret);
            if num == syscall::consts::SYS_EXECVE {
                if let Some(new_brk) = task::check_execve_redirect(cx) {
                    syscall::imp::sync_brk(task::current_pid(), new_brk);
                    syscall::imp::close_cloexec_fds_on_exec(task::current_pid());
                    let tid = {
                        let current = task::current_tid();
                        if current == 0 { task::current_pid() } else { current }
                    };
                    syscall::imp::signal::reset_on_exec(task::current_pid(), tid);
                }
            }
            user_return_work_if_needed(cx);
        }
        TrapCause::PageFault { vaddr, flags } => {
            let token = task::current_user_token();
            #[cfg(target_arch = "riscv64")]
            let is_store = flags == 15;
            #[cfg(target_arch = "riscv64")]
            let is_exec = flags == 12;
            #[cfg(target_arch = "loongarch64")]
            let is_store = flags == 2 || flags == 4;
            #[cfg(target_arch = "loongarch64")]
            let is_exec = flags == 3 || flags == 6;
