// 从内嵌 ELF 和文件系统路径加载用户程序。
use crate::log;
use task;
use fs;
use mm;
use syscall;

include!(concat!(env!("OUT_DIR"), "/apps_data.rs"));

const MAX_TESTCASES: usize = 32;

/// 内嵌用户程序元数据。elf_data 指向 build.rs 生成的内核 rodata 段。
#[derive(Clone, Copy)]
pub struct TestCase {
    pub name: &'static str,
    pub elf_data: &'static [u8],
}

pub fn testcase_list() -> ([Option<TestCase>; MAX_TESTCASES], usize) {
    let mut list: [Option<TestCase>; MAX_TESTCASES] = [None; MAX_TESTCASES];
    let n = APP_COUNT.min(MAX_TESTCASES);
    for i in 0..n { list[i] = Some(TestCase { name: APP_NAMES[i], elf_data: get_app_data(i) }); }
    (list, n)
}

pub fn find_testcase(name: &str) -> Option<TestCase> {
    let n = APP_COUNT.min(MAX_TESTCASES);
    for i in 0..n {
        if APP_NAMES[i] == name {
            return Some(TestCase { name: APP_NAMES[i], elf_data: get_app_data(i) });
        }
    }
    None
}

/// 以内嵌 ELF 创建用户进程并挂载 stdio。
pub fn spawn_embedded(tc: &TestCase) -> usize {
    let pid = task::spawn_from_memory(tc.elf_data, &[tc.name], None, None, 0);
    if pid != 0 {
        syscall::imp::init_stdio(pid);
    }
    pid
}

/// user_init 不可用时的 fallback：遍历所有内嵌 ELF 逐个启动。
pub fn run_embedded_tests() -> usize {
    let (list, count) = testcase_list();
    if count == 0 { return 0; }
    let mut spawned: usize = 0;
    for i in 0..count {
        if let Some(ref tc) = list[i] {
            if tc.elf_data.len() < 1024 { continue; }
            let pid = spawn_embedded(tc);
            if pid != 0 { spawned += 1; }
        }
    }
    spawned
}

fn read_elf(path: &str) -> &'static [u8] {
    static mut FILE_BUF: [u8; 0x200_000] = [0; 0x200_000];
    let buf = unsafe { &mut FILE_BUF };
    match fs::open::sys_open(path).ok().and_then(|h| fs::open::sys_read(&h, buf, 0).ok()).filter(|&n| n > 0) {
        Some(n) => unsafe { &FILE_BUF[..n] },
        None => &[],
    }
}

fn load_elf_interp(path: &str, space: &mut mm::AddressSpace) -> Option<usize> {
    static mut INTERP_BUF: [u8; 0x200_000] = [0; 0x200_000];
    let data = match fs::open::sys_open(path).ok()
        .and_then(|h| fs::open::sys_read(&h, unsafe { &mut INTERP_BUF }, 0).ok())
        .filter(|&n| n > 0)
    { Some(n) => unsafe { &INTERP_BUF[..n] }, None => return None };
    let elf = mm::parse_elf(data).ok()?;
    let base = task::DL_INTERP_OFFSET;
    let token = space.token();
    for i in 0..elf.seg_count {
        let seg = &elf.segments[i];
        if mm::load_segment_to_space(space, token, data, seg, base).is_err() {
            return None;
        }
    }
    Some(elf.entry + base)
}

/// 从文件系统加载 ELF（支持 PT_INTERP 动态链接）。
/// 解释器路径未找到时通过 fallback 映射表适配 musl/glibc 双布局。
pub fn spawn(path: &str, argv: &[&str]) -> usize {
    let data = read_elf(path);
    if data.is_empty() { return 0; }
    let elf = match mm::parse_elf(data) { Ok(e) => e, Err(_) => return 0 };
    let (space, interp_entry, interp_base) = if elf.interp_len > 0 {
        let interp_str = core::str::from_utf8(&elf.interp_path[..elf.interp_len]).unwrap_or("");
        let mut space = match mm::AddressSpace::new_user() { Ok(s) => s, Err(_) => return 0 };
        match load_elf_interp(interp_str, &mut space) {
            Some(e) => (Some(space), Some(e), task::DL_INTERP_OFFSET),
            None => {
                let fallbacks: &[&str] = match interp_str {
                    "/lib/ld-linux-riscv64-lp64d.so.1" => &[
                        "/glibc/lib/ld-linux-riscv64-lp64d.so.1",
                        "/musl/lib/libc.so",
                    ],
                    "/lib/ld-musl-riscv64-sf.so.1" => &[
                        "/musl/lib/libc.so",
                        "/musl/lib/ld-musl-riscv64-sf.so.1",
                    ],
                    "/lib/ld-linux-loongarch-lp64d.so.1"
                    | "/lib/ld-linux-loongarch64-lp64d.so.1"
                    | "/lib64/ld-linux-loongarch-lp64d.so.1"
                    | "/lib64/ld-linux-loongarch64-lp64d.so.1" => &[
                        "/glibc/lib/ld-linux-loongarch-lp64d.so.1",
                    ],
                    "/lib/ld-musl-loongarch64-lp64d.so.1"
                    | "/lib/ld-musl-loongarch-lp64d.so.1"
                    | "/lib64/ld-musl-loongarch64-lp64d.so.1"
                    | "/lib64/ld-musl-loongarch-lp64d.so.1"
                    | "/lib/ld-musl-loongarch64.so.1"
                    | "/lib64/ld-musl-loongarch64.so.1" => &[
                        "/musl/lib/libc.so",
                        "/musl/lib/ld-musl-loongarch64-lp64d.so.1",
                        "/musl/lib/ld-musl-loongarch-lp64d.so.1",
                        "/musl/lib/ld-musl-loongarch64.so.1",
                    ],
                    "/lib/libc.so.6" => &[
                        "/glibc/lib/libc.so",
                        "/glibc/lib/libc.so.6",
                        "/musl/lib/libc.so",
                    ],
                    "/lib/libm.so.6" => &[
                        "/glibc/lib/libm.so",
                        "/glibc/lib/libm.so.6",
                    ],
                    _ => &[],
                };
                let mut found = false;
                let mut entry = 0usize;
                for &fb in fallbacks {
                    if let Some(e) = load_elf_interp(fb, &mut space) {
                        entry = e;
                        found = true;
                        break;
                    }
                }
                if found { (Some(space), Some(entry), task::DL_INTERP_OFFSET) }
                else { return 0 }
            }
        }
    } else { (None, None, 0) };
    let pid = task::spawn_from_memory(data, argv, space, interp_entry, interp_base);
    if pid != 0 { syscall::imp::init_stdio(pid); }
    pid
}

// HAL crate —— 硬件抽象层。
//
// common/    定义所有架构无关的 trait（合约层）。
// rv64/      RISC-V 64 实现，通过 #[cfg(target_arch = "riscv64")] 编译。
// la64/      LoongArch 64 实现，通过 #[cfg(target_arch = "loongarch64")] 编译。
//
// 上层 crate 仅依赖 `hal::Arch`、`hal::TrapContext` 等导出的类型别名，
// 不直接引用架构实现模块，新增架构只需实现 trait 并添加 cfg 分支。

#![no_std]

// ===== trait 定义（所有架构共享） =====
pub mod common;

// ===== 架构实现（编译时二选一） =====
#[cfg(target_arch = "riscv64")]
mod rv64;
#[cfg(target_arch = "riscv64")]
pub use rv64::RV64 as Arch;
#[cfg(target_arch = "riscv64")]
pub use rv64::TrapContext;

#[cfg(target_arch = "loongarch64")]
mod la64;
#[cfg(target_arch = "loongarch64")]
pub use la64::LA64 as Arch;
#[cfg(target_arch = "loongarch64")]
pub use la64::TrapContext;

// Re-export common types
pub use common::*;

// HAL trait 定义模块 —— 架构无关的接口契约。
//
// 每个子模块定义一个细粒度 trait（ArchInfo、ArchTrap、ArchMemory 等），
// 最终由 ArchFull 组合为完整的架构能力集合。架构实现（rv64/la64）
