// ArchMemory, ArchPageTable, MapFlags —— 跨架构页表抽象。
//
// MapFlags 为架构无关的映射权限位，各架构实现负责将其转换为自身的 PTE 编码。
// ArchPageTable 定义页表操作接口（map/unmap/translate/activate）。
// ArchMemory 是架构级内存管理能力，提供 phys_to_virt、TLB/ICache 刷新等操作。
use bitflags::bitflags;

bitflags! {
    #[derive(Clone, Copy, Debug)]
    pub struct MapFlags: usize {
        const READ     = 1 << 0;
        const WRITE    = 1 << 1;
        const EXECUTE  = 1 << 2;
        const USER     = 1 << 3;
        const GLOBAL   = 1 << 4;
        const COW      = 1 << 5;
        const DEVICE   = 1 << 6;
        const NO_CACHE = 1 << 7;
    }
}

pub trait PageTableEntry {
    fn is_valid(&self) -> bool;
    fn is_leaf(&self) -> bool;
    fn ppn(&self) -> usize;
}

pub trait ArchPageTable {
    type Entry: PageTableEntry;
    fn new(root_ppn: usize) -> Self;
    fn root_ppn(&self) -> usize;
    fn map(&mut self, vaddr: usize, paddr: usize, size: usize, flags: MapFlags) -> Result<(), &'static str>;
    fn unmap(&mut self, vaddr: usize, size: usize) -> Result<(), &'static str>;
    fn translate(&self, vaddr: usize) -> Option<usize>;
    fn find_pte(&self, vaddr: usize) -> Option<&Self::Entry>;
    fn activate(&self);
}

pub trait ArchMemory: Sized {
    type PageTable: ArchPageTable;
    type PTE: PageTableEntry;
    fn phys_to_virt(paddr: usize) -> usize;
    fn virt_to_phys(vaddr: usize) -> Option<usize>;
    fn va_width() -> usize;
    fn flush_tlb(vaddr: Option<usize>);
    fn flush_icache_all();
}
