// ArchTrap, ArchTrapContext, TrapCause —— 异常/陷入抽象。
//
// TrapCause 将两个架构的异常编码统一为内核可处理的枚举值。
// ArchTrapContext 封装了 trap 上下文的寄存器读写，屏蔽 RISC-V x10(x17)/LoongArch $r4($r11) 等差异。
// ArchTrap 负责 trap 入口设置和 handler 注册。

/// 统一的异常/中断原因枚举。
///
/// 由各架构的 trap handler 将 scause（RISC-V）或 ESTAT.Ecode（LoongArch）
/// 映射为此枚举后分发给上层处理。
#[derive(Debug, Clone, Copy)]
pub enum TrapCause {
    /// 用户态 ecall/syscall，携带系统调用号。
    UserEcallsyscall(usize),
    /// S 态 ecall（内核内部调用，当前未使用）。
    SupervisorEcallsyscall(usize),
    /// 定时器中断，调度器的时钟 tick 来源。
    SupervisorTimer,
    /// 缺页异常，携带虚拟地址和架构相关标志位。
    PageFault { vaddr: usize, flags: usize },
    /// 非法指令异常。
    IllegalInstruction { scause: usize, stval: usize },
    /// 断点异常（调试用）。
    Breakpoint,
    /// 未识别的异常（用于诊断）。
    Unknown(usize),
}

/// trap 上下文的统一操作接口。
///
/// 每个架构的 TrapContext 结构体字段布局和寄存器编号不同，
/// 但通过此 trait 向上层提供一致的读写方法。
pub trait ArchTrapContext {
    /// 创建新的用户态 trap 上下文：设置入口地址、用户栈顶。
    fn new(entry: usize, ustack_top: usize, hartid: usize) -> Self;
    /// 设置系统调用返回值（写入 a0 寄存器）。
    fn set_syscall_ret(&mut self, ret: isize);
    /// 读取系统调用参数（a0-a5 共 6 个）。
    fn get_syscall_args(&self) -> [usize; 6];
    /// 将异常返回 PC 推进一条指令（跳过 ecall/syscall）。
    fn advance_pc(&mut self);
    /// 设置/读取 sepc/ERA（异常返回地址）。
    fn set_sepc(&mut self, sepc: usize);
    fn get_sepc(&self) -> usize;
    /// 设置/读取用户栈指针 sp。
    fn set_sp(&mut self, sp: usize);
    fn get_sp(&self) -> usize;
    /// 设置 TLS 指针（线程局部存储寄存器）。
    fn set_tls(&mut self, _tls: usize) {}
    /// 保存用户页表 token，供返回用户态时恢复。
    fn set_user_token(&mut self, _token: usize) {}
    /// 保存内核栈指针，供 re-entrant trap 使用。
    fn set_kernel_sp(&mut self, _kernel_sp: usize) {}
    /// 设置 execve 之后的入口参数：argc、argv、envp。
    fn set_entry_args(&mut self, argc: usize, argv: usize, envp: usize);
    /// 在用户栈上构造信号帧，设置返回后跳转到信号处理函数。
    fn signal_frame_setup(
        &mut self,
        handler: usize,
        sig: usize,
        siginfo: usize,
        ucontext: usize,
        trampoline: usize,
    );
    /// 从信号帧恢复现场，返回 (sp, sepc)。
    fn signal_frame_restore(&mut self) -> (usize, usize);
}

/// 架构 trap 控制接口。
pub trait ArchTrap {
    /// 关联的 trap 现场类型。
    type Context: ArchTrapContext;
    /// 启用/禁用用户态 trap（当前为空操作，保留接口）。
    fn enable_user_trap();
    fn disable_user_trap();
    /// 设置 trap 向量基址（RISC-V stvec / LoongArch EENTRY）。
    fn set_trap_vector(addr: usize);
    /// 设置 TLB refill 向量（LoongArch 特有，RISC-V 默认为空操作）。
    fn set_tlb_refill_vector(_addr: usize) {}
    /// 注册内核 trap 分发回调。
    fn set_kernel_trap_handler(handler: fn(&mut Self::Context, TrapCause));
    /// 记录待返回用户态的 trap 上下文引用。
    fn set_return_trap_context(ctx: &Self::Context);
}

