// RISC-V Sv39 三级页表实现（4KB 页，9/9/9 bit VPN 拆分）。
//
// 提供 Sv39PTE（页表项）、Sv39PageTable（页表操作）和 ArchMemory 的 RV64 实现。
// 映射时通过 mm hooks 回调 mm crate 分配中间级页表页，避免循环依赖。

use crate::common::{ArchMemory, ArchPageTable, MapFlags, PageTableEntry};

use super::RV64;

// Sv39 PTE 标志位
pub mod pte_flags {
    pub const V: usize = 1 << 0;
    pub const R: usize = 1 << 1;
    pub const W: usize = 1 << 2;
    pub const X: usize = 1 << 3;
    pub const U: usize = 1 << 4;
    pub const G: usize = 1 << 5;
    pub const A: usize = 1 << 6;
    pub const D: usize = 1 << 7;
    pub const KERNEL_RW: usize = V | R | W | A | D;
    pub const KERNEL_RWX: usize = V | R | W | X | A | D;
    pub const USER_R: usize = V | U | R | A;
    pub const USER_RW: usize = V | U | R | W | A | D;
    pub const USER_RX: usize = V | U | R | X | A;
    pub const USER_RWX: usize = V | U | R | W | X | A | D;
}

/// Sv39 页表项 —— 一个 usize 的 PTE。
#[derive(Clone, Copy)]
pub struct Sv39PTE(pub usize);

impl PageTableEntry for Sv39PTE {
    fn is_valid(&self) -> bool { self.0 & pte_flags::V != 0 }
    fn is_leaf(&self) -> bool {
        self.is_valid() && (self.0 & (pte_flags::R | pte_flags::W | pte_flags::X) != 0)
    }
    fn ppn(&self) -> usize { (self.0 >> 10) & ((1usize << 44) - 1) }
}

/// Sv39 三级页表。
pub struct Sv39PageTable {
    root_ppn: usize,
}

impl Sv39PageTable {
    pub fn map_flags_to_pte(flags: MapFlags) -> usize {
        let mut pte = pte_flags::V;
        if flags.contains(MapFlags::READ)    { pte |= pte_flags::R; }
        if flags.contains(MapFlags::WRITE)   { pte |= pte_flags::W | pte_flags::D; }
        if flags.contains(MapFlags::EXECUTE) { pte |= pte_flags::X; }
        if flags.contains(MapFlags::USER)    { pte |= pte_flags::U; }
        pte |= pte_flags::A;
        pte
    }
}

impl ArchPageTable for Sv39PageTable {
    type Entry = Sv39PTE;

    fn new(root_ppn: usize) -> Self { Self { root_ppn } }

    fn root_ppn(&self) -> usize { self.root_ppn }

    fn map(&mut self, vaddr: usize, paddr: usize, _size: usize, flags: MapFlags) -> Result<(), &'static str> {
        let pte_flags = Self::map_flags_to_pte(flags);
        let pgd_idx = (vaddr >> 30) & 0x1ff;
        let pmd_idx = (vaddr >> 21) & 0x1ff;
        let pte_idx = (vaddr >> 12) & 0x1ff;

        let pgd = unsafe { &mut *((self.root_ppn * 4096) as *mut [usize; 512]) };

        // 分配 PMD
        if pgd[pgd_idx] & pte_flags::V == 0 {
            let pmd_ppn = mm_alloc_page()?;
            mm_zero_page(pmd_ppn);
            pgd[pgd_idx] = (pmd_ppn << 10) | pte_flags::V;
        }
        let pmd_ppn = (pgd[pgd_idx] >> 10) & ((1usize << 44) - 1);
        let pmd = unsafe { &mut *((pmd_ppn * 4096) as *mut [usize; 512]) };

        // 分配 PTE 页
        if pmd[pmd_idx] & pte_flags::V == 0 {
            let pte_ppn = mm_alloc_page()?;
            mm_zero_page(pte_ppn);
            pmd[pmd_idx] = (pte_ppn << 10) | pte_flags::V;
        }
        let pte_ppn = (pmd[pmd_idx] >> 10) & ((1usize << 44) - 1);
        let ptes = unsafe { &mut *((pte_ppn * 4096) as *mut [usize; 512]) };

        ptes[pte_idx] = (paddr / 4096) << 10 | pte_flags;
        Ok(())
    }

    fn unmap(&mut self, vaddr: usize, _size: usize) -> Result<(), &'static str> {
        let pgd_idx = (vaddr >> 30) & 0x1ff;
        let pmd_idx = (vaddr >> 21) & 0x1ff;
        let pte_idx = (vaddr >> 12) & 0x1ff;

        let pgd = unsafe { &*((self.root_ppn * 4096) as *const [usize; 512]) };
        if pgd[pgd_idx] & pte_flags::V == 0 { return Ok(()); }
        let pmd_ppn = (pgd[pgd_idx] >> 10) & ((1usize << 44) - 1);

        let pmd = unsafe { &*((pmd_ppn * 4096) as *const [usize; 512]) };
        if pmd[pmd_idx] & pte_flags::V == 0 { return Ok(()); }
        let pte_ppn = (pmd[pmd_idx] >> 10) & ((1usize << 44) - 1);

        let ptes = unsafe { &mut *((pte_ppn * 4096) as *mut [usize; 512]) };
        ptes[pte_idx] = 0;
        Ok(())
    }

    fn translate(&self, vaddr: usize) -> Option<usize> {
        let pgd_idx = (vaddr >> 30) & 0x1ff;
        let pmd_idx = (vaddr >> 21) & 0x1ff;
        let pte_idx = (vaddr >> 12) & 0x1ff;

        let pgd = unsafe { &*((self.root_ppn * 4096) as *const [usize; 512]) };
        if pgd[pgd_idx] & pte_flags::V == 0 { return None; }
        let pmd_ppn = (pgd[pgd_idx] >> 10) & ((1usize << 44) - 1);

        let pmd = unsafe { &*((pmd_ppn * 4096) as *const [usize; 512]) };
        if pmd[pmd_idx] & pte_flags::V == 0 { return None; }
        let pte_ppn = (pmd[pmd_idx] >> 10) & ((1usize << 44) - 1);

        let ptes = unsafe { &*((pte_ppn * 4096) as *const [usize; 512]) };
        let pte = ptes[pte_idx];
        if pte & pte_flags::V == 0 { return None; }
        Some(((pte >> 10) & ((1usize << 44) - 1)) * 4096 + (vaddr & 0xfff))
    }

    fn find_pte(&self, vaddr: usize) -> Option<&Self::Entry> {
        // 简化实现：返回 None，调用者直接操作原始页表
        None
    }

    fn activate(&self) {
        let satp = (8usize << 60) | self.root_ppn; // MODE=Sv39
        unsafe {
            core::arch::asm!("csrw satp, {}", in(reg) satp);
            core::arch::asm!("sfence.vma");
        }
    }
}

