// ===== 内存分配钩子 —— 由 mm crate 在初始化时注册 =====
//
// HAL 的页表 map 操作需要分配中间级页表页（PMD/PTE 页），
// 但 HAL 不应直接依赖 mm crate。通过这两个函数指针钩子，
// mm crate 在 init 流程中注册其 alloc_page/zero_page 实现，
// HAL 即可间接使用 mm 的分配能力，打破 HAL ↔ mm 的循环依赖。

static mut ALLOC_PAGE_FN: Option<fn() -> Result<usize, &'static str>> = None;
static mut ZERO_PAGE_FN: Option<fn(usize)> = None;

/// 由 mm crate 在初始化时调用，注册页面分配和清零函数。
pub fn set_mm_hooks(
    alloc: fn() -> Result<usize, &'static str>,
    zero: fn(usize),
) {
    unsafe {
        ALLOC_PAGE_FN = Some(alloc);
        ZERO_PAGE_FN = Some(zero);
    }
}

fn mm_alloc_page() -> Result<usize, &'static str> {
    unsafe { ALLOC_PAGE_FN.expect("mm hooks not set")() }
}

fn mm_zero_page(ppn: usize) {
    unsafe { ZERO_PAGE_FN.expect("mm hooks not set")(ppn); }
}

