// ── Error types ────────────────────────────────────────────────────────────

/// Kernel error codes used throughout the mm subsystem.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum KernelError {
    /// Generic invalid argument / state.
    Invalid,
    /// Requested entry does not exist (e.g. missing PTE).
    NoEntry,
    /// Physical memory exhausted.
    NoMemory,
    /// Page fault — address not mapped with required permissions.
    PageFault,
    /// Operation not yet implemented.
    Unimplemented,
}

/// Convenience result alias.
pub type KernelResult<T> = Result<T, KernelError>;

pub type UserFaultHandler = fn(usize, usize, bool) -> bool;

static USER_FAULT_HANDLER: AtomicUsize = AtomicUsize::new(0);

/// Register the task-layer helper used by user copy routines to fault in lazy
/// user pages before retrying the page-table translation.
pub fn set_user_fault_handler(handler: UserFaultHandler) {
    USER_FAULT_HANDLER.store(handler as usize, Ordering::Release);
}

fn fault_in_user_copy(addr: usize, len: usize, write: bool) -> bool {
    let handler = USER_FAULT_HANDLER.load(Ordering::Acquire);
    if handler == 0 {
        return false;
    }
    let handler: UserFaultHandler = unsafe { core::mem::transmute(handler) };
    handler(addr, len, write)
}

