// ── Copy-in / copy-out ────────────────────────────────────────────────────

/// Copy data from a user address space into a kernel buffer.
pub fn copyin(token: usize, src: usize, dst: &mut [u8]) -> KernelResult<()> {
    copy_with_translation(token, src, dst)
}

/// Copy data from a kernel buffer into a user address space.
///
/// Kernel writes go through the direct-mapped physical alias, so they must
/// first resolve the destination as a write access.  Otherwise copyout would
/// bypass hardware faults and corrupt a fork-shared COW page.
pub fn copyout(token: usize, dst: usize, src: &[u8]) -> KernelResult<()> {
    let mut offset = 0;
    while offset < src.len() {
        let va = dst + offset;
        let page_offset = va % PAGE_SIZE;
        let len = core::cmp::min(PAGE_SIZE - page_offset, src.len() - offset);
        let pa = match translate_user_write(token, VirtAddr(va)) {
            Ok(pa) => pa.0,
            Err(err) => {
                if !fault_in_user_copy(va, len, true) {
                    return Err(err);
                }
                translate_user_write(token, VirtAddr(va))?.0
            }
        };
        unsafe {
            copy_bytes_exact(
                src.as_ptr().add(offset),
                phys_to_virt(pa) as *mut u8,
                len,
            );
        }
        offset += len;
    }
    Ok(())
}

/// Fill a user buffer with zero bytes.
///
/// This is the /dev/zero hot path: it keeps the same write-translation and
/// COW behavior as copyout(), but avoids building a kernel scratch buffer.
pub fn copyout_zero(token: usize, dst: usize, len: usize) -> KernelResult<()> {
    let mut offset = 0;
    while offset < len {
        let va = dst + offset;
        let page_offset = va % PAGE_SIZE;
        let chunk = core::cmp::min(PAGE_SIZE - page_offset, len - offset);
        let pa = match translate_user_write(token, VirtAddr(va)) {
            Ok(pa) => pa.0,
            Err(err) => {
                if !fault_in_user_copy(va, chunk, true) {
                    return Err(err);
                }
                translate_user_write(token, VirtAddr(va))?.0
            }
        };
        unsafe {
            core::ptr::write_bytes(phys_to_virt(pa) as *mut u8, 0, chunk);
        }
        offset += chunk;
    }
    Ok(())
}

fn copy_with_translation(token: usize, src: usize, dst: &mut [u8]) -> KernelResult<()> {
    let mut offset = 0;
    while offset < dst.len() {
        let va = src + offset;
        let page_offset = va % PAGE_SIZE;
        let len = core::cmp::min(PAGE_SIZE - page_offset, dst.len() - offset);
        let pa = match translate_user(token, VirtAddr(va)) {
            Ok(pa) => pa.0,
            Err(err) => {
                if !fault_in_user_copy(va, len, false) {
                    return Err(err);
                }
                translate_user(token, VirtAddr(va))?.0
            }
        };
        unsafe {
            copy_bytes_exact(
                phys_to_virt(pa) as *const u8,
                dst.as_mut_ptr().add(offset),
                len,
            );
        }
        offset += len;
    }
    Ok(())
}

