pub fn current_user_token() -> usize {
    let token = current_task_token();
    if token != 0 {
        return token;
    }
    process_table()
        .with(current_pid(), |p| p.token)
        .unwrap_or(0)
}

pub fn handle_lazy_mmap_fault(vaddr: usize, is_store: bool, is_exec: bool) -> bool {
    let pid = current_pid();
    let token = current_user_token();
    if token == 0 {
        return false;
    }
    let va = mm::align_down(vaddr, mm::PAGE_SIZE);
    let vma = match process_table().with(pid, |proc| proc.find_vma(vaddr)).flatten() {
        Some(vma) => vma,
        None => return false,
    };
    if !vma_allows_fault(vma.flags, is_store, is_exec) {
        return false;
    }
    if mm::translate(token, mm::VirtAddr(va)).is_ok() {
        return true;
    }
    if let Some(backing_id) = vma.anon_shared_id {
        let page_index = va.saturating_sub(vma.start) / mm::PAGE_SIZE;
        let ppn = match mm::anon_shared_get_page(backing_id, page_index) {
            Ok(ppn) => ppn,
            Err(_) => return false,
        };
        if mm::map_user_page_by_token(token, mm::VirtAddr(va), ppn, vma.flags).is_err() {
            mm::dec_page_ref(ppn);
            return false;
        }
        return true;
    }
    let ppn = match mm::map_user_by_token(token, mm::VirtAddr(va), vma.flags) {
        Ok(ppn) => ppn,
        Err(_) => return false,
    };
    mm::zero_page(ppn);

    let Some(file) = vma.file else {
        return true;
    };
    let file_offset = file
        .file_offset
        .saturating_add(va.saturating_sub(file.mapping_start));
    let read_len = mm::PAGE_SIZE.min(vma.end.saturating_sub(va));
    let dst = unsafe {
        core::slice::from_raw_parts_mut(
            mm::phys_to_virt(ppn.0 * mm::PAGE_SIZE) as *mut u8,
            read_len,
        )
    };
    let mt = fs::init::mount_table();
    let loaded = if file.fs_idx == 0xFFFE {
        mt.ramfs()
            .and_then(|ramfs| ramfs.read_file(file.inode, file_offset, dst).ok())
            .is_some()
    } else {
        mt.get_ext4(file.fs_idx)
            .and_then(|ext4fs| ext4fs.read_file(file.inode, file_offset, dst).ok())
            .is_some()
    };
    if loaded {
        true
    } else {
        let _ = mm::unmap_user_by_token(token, mm::VirtAddr(va));
        mm::dec_page_ref(ppn);
        false
    }
}

#[cfg(target_arch = "riscv64")]
fn vma_allows_fault(flags: usize, is_store: bool, is_exec: bool) -> bool {
    if flags & (mm::pte_flags::R | mm::pte_flags::W | mm::pte_flags::X) == 0 {
        return false;
    }
    if is_store && flags & mm::pte_flags::W == 0 {
        return false;
    }
    if is_exec && flags & mm::pte_flags::X == 0 {
        return false;
    }
    true
}

#[cfg(target_arch = "loongarch64")]
fn vma_allows_fault(flags: usize, is_store: bool, _is_exec: bool) -> bool {
    if flags & (mm::pte_flags::P | mm::pte_flags::U) != (mm::pte_flags::P | mm::pte_flags::U) {
        return false;
    }
    if is_store && flags & mm::pte_flags::W == 0 {
        return false;
    }
    true
}

pub fn fault_in_user_read(addr: usize, len: usize) -> bool {
    fault_in_user_range(addr, len, false)
}

pub fn fault_in_user_write(addr: usize, len: usize) -> bool {
    fault_in_user_range(addr, len, true)
}

fn fault_in_user_range(addr: usize, len: usize, write: bool) -> bool {
    if len == 0 {
        return true;
    }
    let token = current_user_token();
    if token == 0 {
        return false;
    }
    let Some(end) = addr.checked_add(len - 1) else {
        return false;
    };
    let mut va = mm::align_down(addr, mm::PAGE_SIZE);
    let last = mm::align_down(end, mm::PAGE_SIZE);
    loop {
        let ready = if write {
            mm::ensure_user_write(token, mm::VirtAddr(va)).is_ok()
        } else {
            mm::translate(token, mm::VirtAddr(va)).is_ok()
        };
        if !ready {
            if !handle_lazy_mmap_fault(va, write, false) {
                return false;
            }
            let mapped = if write {
                mm::ensure_user_write(token, mm::VirtAddr(va)).is_ok()
            } else {
                mm::translate(token, mm::VirtAddr(va)).is_ok()
            };
            if !mapped {
                return false;
            }
        }
        if va == last {
            break;
        }
        va += mm::PAGE_SIZE;
    }
    true
}

fn user_copy_fault_handler(addr: usize, len: usize, write: bool) -> bool {
    fault_in_user_range(addr, len, write)
}

/// Initialise the task / scheduler subsystem.
