impl ExitStatus {
    pub const fn wait_status(self) -> u32 {
        match self {
            // wait(2): WIFEXITED status stores the low 8 bits in bits 8..15.
            Self::Exited(code) => ((code as u32) & 0xff) << 8,
            // wait(2): WIFSIGNALED status stores the signal in bits 0..6 and
            // the optional core-dump flag in bit 7.
            Self::Signaled {
                signal,
                core_dumped,
            } => ((signal as u32) & 0x7f) | if core_dumped { 0x80 } else { 0 },
        }
    }
}

/// 进程结构。
///
/// 每个 Process 可以包含多个线程（tid → Thread）。
/// 父子关系通过 parent_pid 和 children 集合维护。
/// 退出时变为 Zombie 状态，由父进程 wait4 回收。
#[derive(Clone)]
pub struct Process {
    /// 进程 ID。
    pub pid: Pid,
    /// 父进程 PID。
    pub parent_pid: Pid,
    /// 线程组 ID（tgid，当前等于 pid，单线程时）。
    pub tgid: Pid,
    /// POSIX process-group ID.
    pub pgid: Pid,
    /// POSIX session ID.
    pub sid: Pid,
    /// 进程状态。
    pub status: TaskStatus,
    /// 该进程包含的所有线程。
    pub threads: BTreeMap<usize, Thread>,
    /// 子进程 PID 集合。
    pub children: BTreeMap<Pid, ()>,
    /// 退出码（仅在 Zombie 状态有效）。
    pub exit_code: i32,
    pub exit_status: ExitStatus,
    pub group_exit: bool,
    pub group_exit_status: ExitStatus,
    /// 是否已被父进程通过 wait4 回收。
    pub reaped: bool,
    /// 程序断点（brk，数据段末尾，页对齐）。
    pub brk: usize,
    /// SATP token / 页表根标识。
    pub token: usize,
    /// 根页表物理页号。
    pub root_ppn: usize,
    /// 文件描述符表。
    pub fd_table: [Option<FdEntry>; MAX_FD],
    /// 当前工作目录。
    pub cwd: [u8; MAX_CWD_LEN],
    pub cwd_len: usize,
    /// mmap anonymous region next free address (like 148's mmap_top).
    pub mmap_anon_base: usize,
    /// mmap file-backed region next free address.
    pub mmap_file_base: usize,
    pub vmas: Vec<VmArea>,
    /// Monotonic counter bumped whenever one child exits.
    pub child_exit_epoch: usize,
    /// Whether a parent is currently waiting for a child-exit event.
    pub should_wake: bool,
    /// Scheduler entry to wake when a child-exit event arrives.
    pub wait_waker: usize,
    pub start_time_nanos: u64,
    pub comm: [u8; TASK_COMM_LEN],
    pub resource_limits: ResourceLimits,
}

impl Process {
    /// 创建新进程。
    pub fn new(pid: Pid, parent_pid: Pid) -> Self {
        let mut fd_table: [Option<FdEntry>; MAX_FD] = [None; MAX_FD];
        fd_table[0] = Some(FdEntry::Stdin);
        fd_table[1] = Some(FdEntry::Stdout);
        fd_table[2] = Some(FdEntry::Stderr);

        Self {
            pid,
            parent_pid,
            tgid: pid,
            pgid: pid,
            sid: pid,
            status: TaskStatus::Ready,
            threads: BTreeMap::new(),
            children: BTreeMap::new(),
            exit_code: 0,
            exit_status: ExitStatus::Exited(0),
            group_exit: false,
            group_exit_status: ExitStatus::Exited(0),
            reaped: false,
            brk: 0,
            token: 0,
            root_ppn: 0,
            fd_table,
            cwd: [b'/'; MAX_CWD_LEN],
            cwd_len: 1,
            mmap_anon_base: 0,
            mmap_file_base: 0,
            vmas: Vec::new(),
            child_exit_epoch: 0,
            should_wake: false,
            wait_waker: 0,
            start_time_nanos: Arch::ticks_to_nanos(Arch::current_ticks()),
            comm: *b"process\0\0\0\0\0\0\0\0\0",
            resource_limits: ResourceLimits::new(),
        }
    }

    pub fn set_comm(&mut self, name: &[u8]) {
        self.comm = [0; TASK_COMM_LEN];
        let mut len = 0usize;
