/// 超级块 trait —— 代表一个已挂载的文件系统实例。
///
/// 每个文件系统实现都应提供自己的 `SuperBlock` 实现，
/// 并通过挂载表注册到 VFS 层。
pub trait SuperBlock {
    /// 返回文件系统的根 inode。
    fn root_inode(&self) -> FsResult<InodeObj>;

    /// 根据 inode 编号读取 inode。
    fn read_inode(&self, ino: u32) -> FsResult<InodeObj>;

    /// 返回文件系统的块大小（字节）。
    fn block_size(&self) -> usize;

    /// 返回文件系统的总块数。
    fn total_blocks(&self) -> u64;

    /// 返回文件系统的空闲块数。
    fn free_blocks(&self) -> u64;

    /// 返回文件系统类型的名称。
    fn total_inodes(&self) -> u64 {
        1
    }

    fn free_inodes(&self) -> u64 {
        1
    }

    fn magic(&self) -> u64 {
        0
    }

    fn fs_name(&self) -> &'static str;

    fn unlink_at(&self, _parent_ino: u32, _name: &str) -> FsResult<()> {
        Err(crate::vfs::FsError::Unsupported)
    }

    fn rmdir_at(&self, _parent_ino: u32, _name: &str) -> FsResult<()> {
        Err(crate::vfs::FsError::Unsupported)
    }
}

/// Inode 对象 —— 包含类型判别和目录/文件操作所需的数据。
///
/// 文件系统实现应将 on-disk 或 in-memory inode 数据封装在此结构中。
#[derive(Clone, Copy)]
pub struct InodeObj {
    /// Inode 模式 (类型 + 权限位)。
    pub mode: u16,
    /// 文件大小 (字节)。
    pub size: u32,
    /// 扩展标志 (如 EXT4_EXTENTS_FL)。
    pub flags: u32,
    /// 用户 ID。
    pub uid: u16,
    /// 组 ID。
    pub gid: u16,
    /// 修改时间。
    pub mtime: u32,
    /// 硬链接计数。
    pub links_count: u16,
    /// 占用的 512 字节扇区数。
    pub blocks: u32,
    /// i_block 原始数据（extent tree 根或直接/间接块指针）。
    pub block: [u32; 15],
}

impl InodeObj {
    /// 创建一个空的 inode 对象（用于虚拟文件系统）。
    pub const fn empty() -> Self {
        InodeObj {
            mode: 0, size: 0, flags: 0, uid: 0, gid: 0,
            mtime: 0, links_count: 0, blocks: 0,
            block: [0; 15],
        }
    }

    /// 判断此 inode 是否为目录。
    pub fn is_dir(&self) -> bool {
        self.mode & 0xF000 == 0x4000
    }

    /// 判断此 inode 是否为常规文件。
    pub fn is_file(&self) -> bool {
        self.mode & 0xF000 == 0x8000
    }

    /// 判断是否为内联数据 inode。
    pub fn is_inline(&self) -> bool {
        self.flags & 0x1000_0000 != 0
    }
}

/// 目录项 trait —— 表示目录中的一个条目。
///
/// 文件系统实现应返回实现了此 trait 的对象，
/// 用于目录遍历（如 `read_dir`）。
pub trait Dentry {
    /// 获取条目的 inode 编号。
    fn inode(&self) -> u32;

    /// 获取条目名称。
    fn name(&self) -> &str;

    /// 获取文件类型（1=常规文件, 2=目录, 0=未知）。
    fn file_type(&self) -> u8;
}

/// 文件操作 trait —— 代表一个打开的文件句柄。
///
/// 不同的文件系统实现提供不同的 `File` 实现。
pub trait File {
    /// 从文件中读取数据。
    ///
    /// 从当前偏移量开始读取，最多读取 `buf.len()` 字节。
    /// 返回实际读取的字节数。返回 0 表示已到达文件末尾。
    fn read(&mut self, buf: &mut [u8]) -> FsResult<usize>;

    /// 向文件中写入数据。
    ///
    /// 从当前偏移量开始写入，最多写入 `buf.len()` 字节。
    /// 返回实际写入的字节数。
    fn write(&mut self, buf: &[u8]) -> FsResult<usize>;

    /// 设置文件读写位置。
    ///
    /// 返回新的偏移量。
    fn seek(&mut self, offset: usize) -> FsResult<usize>;

    /// 返回文件大小（字节）。
    fn size(&self) -> FsResult<usize>;

    /// 返回当前文件偏移量。
    fn offset(&self) -> usize;

    /// 判断是否为目录。
    fn is_dir(&self) -> bool;
}

