//! Device manager — coordinates device discovery, driver probing, and
//! device lifecycle.
//!
//! The main entry point is [`init`], which should be called early during
//! kernel initialization with the device-tree blob address.

use alloc::boxed::Box;
use alloc::vec::Vec;

use crate::traits::{BlockDevice, Device};

/// Holds all discovered and initialized device instances.
static DEVICES: spin::Mutex<Vec<Box<dyn Device>>> = spin::Mutex::new(Vec::new());
static SCRATCH_BLOCK: spin::Mutex<Option<&'static dyn BlockDevice>> = spin::Mutex::new(None);
const SCRATCH_RAM0_BLOCK_SIZE: usize = 512;
const SCRATCH_RAM0_BLOCKS: usize = 1_048_576; // 512 MiB, sparse-backed.

/// Initialize the driver subsystem.
///
/// `dtb_addr` is the physical address of the flattened device tree blob
/// passed by the bootloader (OpenSBI). If 0, the DTB parser will attempt
/// to use a previously saved copy from `.data`.
pub fn init(dtb_addr: usize) {
    // 1. Register all built-in drivers.
    init_drivers();

    // 2. Probe devices discovered via DTB.
    probe_devices(dtb_addr);

    #[cfg(target_arch = "loongarch64")]
    for device in crate::impls::block::virtio_blk_pci::probe_all() {
        DEVICES.lock().push(device);
    }

    init_scratch_block();
}

/// Seed the driver registry with all known built-in drivers.
fn init_drivers() {
    crate::impls::register_all();
}

fn init_scratch_block() {
    if SCRATCH_BLOCK.lock().is_some() {
        return;
    }
    let disk = Box::leak(Box::new(crate::impls::block::ramdisk::RamDisk::new(
        "ram0",
        SCRATCH_RAM0_BLOCK_SIZE,
        SCRATCH_RAM0_BLOCKS,
    )));
    *SCRATCH_BLOCK.lock() = Some(disk as &'static dyn BlockDevice);
}

/// Walk devices discovered from the DTB and try to match them against
/// registered drivers.
fn probe_devices(dtb_addr: usize) {
    let devices = crate::probe::device_tree::discover_devices(dtb_addr);

    for bus_info in &devices {
        crate::registry::for_each_driver(|driver| {
            if let Some(dev) = (driver.probe)(bus_info) {
                DEVICES.lock().push(dev);
            }
        });
    }
}

// ── Public accessors ──────────────────────────────────────────────────

/// Obtain a reference to the first registered block device, if any.
pub fn get_block_device() -> Option<&'static dyn crate::traits::BlockDevice> {
    // Scan the DEVICES list for the first BlockDevice
    for dev in DEVICES.lock().iter() {
        if let Some(bd) = dev.as_block_device() {
            // Safety: DEVICES holds Box<dyn Device> which outlives the returned ref
            return Some(unsafe { core::mem::transmute(bd) });
        }
    }
    None
}

/// Visit every registered block device.
pub fn for_each_block_device(mut f: impl FnMut(&'static dyn crate::traits::BlockDevice)) {
    for dev in DEVICES.lock().iter() {
        if let Some(bd) = dev.as_block_device() {
            // Safety: DEVICES owns the boxed devices for the whole kernel lifetime.
            f(unsafe { core::mem::transmute(bd) });
        }
    }
}

pub fn get_scratch_block_device(index: usize) -> Option<&'static dyn crate::traits::BlockDevice> {
    if index == 0 {
        *SCRATCH_BLOCK.lock()
    } else {
        None
    }
}

/// Obtain a reference to the first registered char device, if any.
pub fn get_char_device() -> Option<&'static dyn crate::traits::CharDevice> {
    crate::impls::char::get_first_char_device()
}

/// Return the number of discovered devices (across all types).
pub fn device_count() -> usize {
    DEVICES.lock().len()
}

