//
// Runtime 维护一个调度器实例，run() 循环执行 poll 调度。
// 从 oskernel2026-goodos kernel-rv task/mod.rs run_until_exit 循环逻辑迁移，
// 改为 async future polling 模型：
//   1. pop 就绪任务
//   2. poll future → Pending/Ready
//   3. Pending → 再入队; Ready → 回收JoinHandle

use alloc::boxed::Box;
use alloc::collections::BTreeMap;
use core::future::Future;
use core::pin::Pin;
use core::task::{Context, Poll, Waker, RawWaker, RawWakerVTable};
use spin::Mutex;

use crate::scheduler::SimpleScheduler;
