/// 存储 future 的内部类型。
type FuturePtr = Pin<Box<dyn Future<Output = ()> + Send>>;

/// 使用该 task_id 标记为 idle 占位。
const IDLE_TASK_ID: usize = 0;

/// 全局 Runtime 单例。
///
/// Runtime 包含调度器和 future 存储（BTreeMap<task_id, FuturePtr>）。
/// run() 循环：
///   1. 从调度器 fetch_next_task() → 获取下一个就绪 entity
///   2. 从 futures 表中取出对应 future
///   3. 调用 poll()：
///      - Ready(()) → 丢弃 future，entity 置为 Zombie
///      - Pending → entity 重新入队
///   4. 如果无就绪且无 pending，返回（idle）
pub struct Runtime {
    scheduler: SimpleScheduler,
    /// 存储所有 active future。
    futures: Mutex<BTreeMap<usize, FuturePtr>>,
    /// 下一个 task_id。
    next_id: Mutex<usize>,
}

impl Runtime {
    /// 创建 Runtime 实例。
    pub fn new() -> Self {
        Self {
            scheduler: SimpleScheduler::new(),
            futures: Mutex::new(BTreeMap::new()),
            next_id: Mutex::new(1), // 0 保留给 idle
        }
    }

    /// 分配新 task_id。
    pub fn alloc_id(&self) -> usize {
        let mut id = self.next_id.lock();
        let tid = *id;
        *id += 1;
        tid
    }

    /// 提交 future 到 Runtime。
    ///
    /// 返回 JoinHandle，调用者可以用它等待结果。
    pub fn submit<F>(&self, future: F) -> JoinHandle<()>
    where
        F: Future<Output = ()> + Send + 'static,
    {
        let tid = self.alloc_id();
        let entity = SchedEntity::new(tid);
        self.scheduler.enqueue(entity);

        let boxed: FuturePtr = Box::pin(future);
        self.futures.lock().insert(tid, boxed);

        JoinHandle::new(tid)
    }

    /// 唤醒指定 task_id 的 future（从 AsyncWaker 调用）。
    pub fn wake_task(&self, task_id: usize) {
        self.scheduler.wake_by_id(task_id);
    }

    /// 阻塞指定 task_id（如睡眠）。
    pub fn block_task(&self, task_id: usize) {
        self.scheduler.block_by_id(task_id);
    }

    /// 运行调度循环。
    ///
    /// 每次 tick：
    ///   1. 从调度器中 fetch_next → 如果 None 则返回（idle）
    ///   2. 从 futures 表中取出对应 future
    ///   3. poll() future
    ///   4. Poll::Pending → entity set_ready 重新入队
    ///   5. Poll::Ready(()) → entity 变为 Zombie，清理
    ///
    /// 返回是否执行了有用工作（至少 poll 了一个 future）。
    pub fn run(&self) -> bool {
        let entity = match self.scheduler.fetch_next() {
            Some(e) => e,
            None => return false,
        };

        let task_id = entity.task_id;
        let mut futures = self.futures.lock();
        let future_opt = futures.remove(&task_id);
        drop(futures);

        if let Some(mut future) = future_opt {
            let waker = self.create_waker(task_id);
            let mut cx = Context::from_waker(&waker);

            match future.as_mut().poll(&mut cx) {
                Poll::Ready(()) => {
                    // Future 完成：丢弃 entity → Zombie
                    let _ = entity;
                }
                Poll::Pending => {
                    // Future 未完成：重新入队
                    let mut entity = SchedEntity::new(task_id);
                    entity.set_ready();
                    self.scheduler.enqueue(entity);
                    // 重新插入 future 表
                    self.futures.lock().insert(task_id, future);
                }
            }
        } else {
            // future 不存在（可能已被取消），实体直接丢弃
            let _ = entity;
        }

        true
    }

    /// 运行直到所有任务完成或全部阻塞。
    ///
    /// 对应 oskernel2026-goodos run_until_exit 的循环语义。
    /// 在 boot 阶段同步等待异步任务。
    pub fn run_until_done(&self) {
        loop {
            let ran = self.run();
            if !ran || self.scheduler.ready_count() == 0 {
                break;
            }
        }
    }

    /// 启动调度循环（永不返回，trampoline 模式）。
    ///
    /// 在有任务的情况下持续调度。当无 Ready 任务时调用 hal::halt()。
    pub fn start(&self) -> ! {
        loop {
            let ran = self.run();
            if !ran {
                // 无就绪任务：halt 等待中断
                #[cfg(target_arch = "riscv64")]
                unsafe { core::arch::asm!("wfi"); }
                #[cfg(target_arch = "loongarch64")]
                unsafe { core::arch::asm!("idle 0"); }
                #[cfg(not(any(target_arch = "riscv64", target_arch = "loongarch64")))]
                unsafe { core::arch::asm!("wfi"); }
            }
        }
    }

    /// 创建 Waker 封装，连接 AsyncWaker ↔ Runtime。
    fn create_waker(&self, task_id: usize) -> Waker {
        // 使用 raw waker 简化实现
        unsafe { Waker::from_raw(self.raw_waker(task_id)) }
    }

    /// 构造 RawWaker。
    fn raw_waker(&self, task_id: usize) -> RawWaker {
        let data = task_id as *const ();
        RawWaker::new(data, &RAW_WAKER_VTABLE)
    }
}

/// 全局 Runtime 单例工厂访问器。
static mut RUNTIME: Option<Runtime> = None;

/// 初始化全局 Runtime。必须在 boot 早期调用。
pub fn init_runtime() {
    unsafe {
        RUNTIME = Some(Runtime::new());
    }
}

/// 获取全局 Runtime 引用。
