#[inline]
fn now_us() -> u64 {
    Arch::ticks_to_nanos(Arch::current_ticks()) / 1_000
}

#[inline]
fn account_task_time(time: &mut TaskTime, now: u64) {
    if time.last_us == 0 {
        time.last_us = now;
        return;
    }
    let delta = now.saturating_sub(time.last_us);
    match time.mode {
        TimeMode::User => {
            time.utime_us = time.utime_us.saturating_add(delta);
        }
        TimeMode::Kernel => {
            time.stime_us = time.stime_us.saturating_add(delta);
        }
        TimeMode::Idle => {}
    }
    time.last_us = now;
}

#[inline]
fn finalized_task_snapshot(task: &mut TaskEntry, now: u64) -> TmsSnapshot {
    account_task_time(&mut task.time, now);
    task.time.mode = TimeMode::Idle;
    task.time.snapshot()
}

fn snapshot_task_time(task: &TaskEntry, now: u64) -> TmsSnapshot {
    let mut time = task.time;
    account_task_time(&mut time, now);
    time.snapshot()
}

fn add_snapshot(total: &mut TmsSnapshot, part: TmsSnapshot) {
    total.utime_us = total.utime_us.saturating_add(part.utime_us);
    total.stime_us = total.stime_us.saturating_add(part.stime_us);
    total.cutime_us = total.cutime_us.saturating_add(part.cutime_us);
    total.cstime_us = total.cstime_us.saturating_add(part.cstime_us);
}

