    #[cfg(target_arch = "riscv64")]
    unsafe {
        core::arch::asm!("csrs sstatus, {0}", in(reg) 1usize << 1);
        core::arch::asm!("wfi");
        core::arch::asm!("csrc sstatus, {0}", in(reg) 1usize << 1);
    }
    #[cfg(target_arch = "loongarch64")]
    unsafe {
        core::arch::asm!("idle 0");
    }
}

