const MAX_TRACKED_PAGES: usize = platform::MEMORY_SIZE / PAGE_SIZE;
const FREE_BITMAP_BYTES: usize = MAX_TRACKED_PAGES / 8;

/// 空闲页位图：每 bit 对应一页（1 = 空闲，0 = 已分配）。
static mut FREE_BITMAP: [u8; FREE_BITMAP_BYTES] = [0; FREE_BITMAP_BYTES];

/// 物理页引用计数数组，与 FREE_BITMAP 并行，覆盖相同页号范围。
static mut PAGE_REFCOUNT: [usize; MAX_TRACKED_PAGES] = [0; MAX_TRACKED_PAGES];

/// 位图覆盖的首个 PPN。
static mut BITMAP_BASE_PPN: usize = 0;

/// 位图覆盖的尾后 PPN（不包含）。
static mut BITMAP_MAX_PPN: usize = 0;

/// 全局物理页分配器。
///
/// 通过位图跟踪空闲页，通过并行的引用计数数组跟踪在用页。
/// 分配始终从位图获取（回收页优先）；因所有可用内存在初始化时已
/// 全部注入位图，不存在 bump 分配回退路径。
pub(super) struct FrameAllocator {
    /// 已分配的最高物理地址（仅用于诊断统计，非 bump 指针）。
    current: usize,
    /// 被跟踪物理地址空间的尾地址。
    end: usize,
    /// 防止未初始化即使用的守卫标志。
    initialized: bool,
}

impl FrameAllocator {
    /// 创建未初始化的分配器（仅 `init()` 之后可用）。
    pub(super) const fn new() -> Self {
        Self {
            current: 0,
            end: 0,
            initialized: false,
        }
    }

    /// 用硬件内存区间初始化分配器，注入空闲页。
    ///
    /// `kernel_end` 是内核镜像末尾物理地址（链接器 `ekernel` 符号，向上页对齐）。
    /// `ranges` 是从 DTB 或平台默认值中获取的可用物理内存区间列表。
    ///
    /// 每个区间中严格位于 `kernel_end` 之上的页均被推入位图。
    /// 内核镜像之下的页面（启动栈、早期数据）因从未入图而被隐式保留。
    ///
    /// # Safety
    /// 必须恰好调用一次，且位于任何 alloc/free 之前。
    pub(super) unsafe fn init_ranges(&mut self, kernel_end: usize, ranges: &[PhysRange]) {
        self.current = 0;
        let tracked_start = align_down(platform::PHYS_MEMORY_START, PAGE_SIZE);
        let tracked_end = tracked_start.saturating_add(MAX_TRACKED_PAGES * PAGE_SIZE);
        self.end = tracked_end;
        self.initialized = true;

        BITMAP_BASE_PPN = tracked_start / PAGE_SIZE;
        BITMAP_MAX_PPN = tracked_end / PAGE_SIZE;
        for b in FREE_BITMAP.iter_mut() {
            *b = 0;
        }
        let mut idx = 0;
        while idx < MAX_TRACKED_PAGES {
            PAGE_REFCOUNT[idx] = 0;
            idx += 1;
        }

        let kernel_end = align_up(kernel_end, PAGE_SIZE);
        for range in ranges {
            let mut start = align_up(range.start, PAGE_SIZE);
            let mut end = align_down(range.end, PAGE_SIZE);
            if end <= start {
                continue;
            }
            if start < tracked_start {
                start = tracked_start;
            }
            if end > tracked_end {
                end = tracked_end;
            }
            if end <= kernel_end {
                continue;
            }
            if start < kernel_end {
                start = kernel_end;
            }
            let mut ppn = start / PAGE_SIZE;
            let end_ppn = end / PAGE_SIZE;
            while ppn < end_ppn {
                bitmap_push(ppn);
                ppn += 1;
            }
        }
    }

    /// 分配单个已清零的物理页。
    ///
    /// 在位图中查找首个空闲页，清除对应位，将 refcount 置 1，
    /// 返回前清零页面内容。位图耗尽或分配器未初始化时返回 `NoMemory`。
    ///
    /// # Safety
    /// 调用者须跟踪返回的 PPN 并最终调用 `free` / `dec_ref`。
    pub(super) unsafe fn alloc(&mut self) -> KernelResult<PhysPageNum> {
        if !self.initialized {
            return Err(KernelError::NoMemory);
        }

        // 从位图中取回收页（优先复用已释放页面）。
        if let Some(ppn) = bitmap_pop() {
            set_refcount(ppn, 1);
            zero_page(PhysPageNum(ppn));
            self.current = self.current.max((ppn + 1) * PAGE_SIZE);
            return Ok(PhysPageNum(ppn));
        }

        Err(KernelError::NoMemory)
    }

    /// 分配 `pages` 个物理连续的已清零页面。
    ///
    /// 在位图中扫描连续空闲段。内核栈和 trap 上下文以线性物理区间编址，
    /// 不能由零散回收页拼凑，因此必须走此路径。
    ///
    /// 若无长度为 `pages` 的连续空闲段或 `pages == 0`，返回 `NoMemory`。
    pub(super) unsafe fn alloc_contiguous(&mut self, pages: usize) -> KernelResult<PhysPageNum> {
        if !self.initialized || pages == 0 {
            return Err(KernelError::NoMemory);
        }

        if let Some(first_ppn) = bitmap_pop_contiguous(pages) {
            for page in 0..pages {
                let ppn = PhysPageNum(first_ppn + page);
                set_refcount(ppn.0, 1);
                zero_page(ppn);
            }
            self.current = self.current.max((first_ppn + pages) * PAGE_SIZE);
            return Ok(PhysPageNum(first_ppn));
        }

        Err(KernelError::NoMemory)
    }

    /// 无条件将页面归还到位图（绕过引用计数）。
    ///
    /// # Safety
    /// 调用者须保证页面确实无人使用 —— 不存在任何其他引用。
    pub(super) unsafe fn free(&mut self, ppn: PhysPageNum) {
        bitmap_push(ppn.0);
    }

    /// 增加引用计数。PPN 越界或当前计数为 0（防 use-after-free）时返回 false。
    pub(super) unsafe fn inc_ref(&mut self, ppn: PhysPageNum) -> bool {
        inc_refcount(ppn.0)
    }

    /// 减少引用计数。仅当计数降为 0 且页面被回收至位图时返回 true。
    ///
    /// 这是 COW 的主释放路径 —— 最后一个共享者释放引用时，
    /// 物理页自动回到空闲池。
    pub(super) unsafe fn dec_ref(&mut self, ppn: PhysPageNum) -> bool {
        match dec_refcount(ppn.0) {
            Some(0) => {
                bitmap_push(ppn.0);
                true
            }
            Some(_) => false,
            None => false,
        }
    }

    /// 查询当前引用计数，PPN 越界时返回 0。
    pub(super) unsafe fn refcount(&self, ppn: PhysPageNum) -> usize {
        get_refcount(ppn.0).unwrap_or(0)
    }

    /// 返回已分配最高物理地址快照（用于 /proc/meminfo）。
    pub(super) fn bump_pa(&self) -> usize {
        self.current
    }
}

// ── /proc/meminfo 快照 ─────────────────────────────────────────────────────

pub(super) fn meminfo_snapshot(current_pa: usize) -> (usize, usize) {
