#[inline(never)]
pub fn sys_kill(pid: usize, sig: usize) -> isize {
    if sig >= MAX_SIGNALS {
        return EINVAL;
    }

    let pid_arg = pid as isize;
    let targets = task::process_table().kill_process_targets(pid_arg, task::current_pid());
    if targets.is_empty() {
        return ESRCH;
    }

    if sig != 0 {
        for target in targets.iter().copied() {
            send_process_signal_code(target, sig, SI_USER);
        }
    }
    0
}

pub fn send_signal(pid: usize, sig: usize) {
    send_process_signal_code(pid, sig, SI_USER);
}

pub fn send_signal_tid(tid: usize, sig: usize) {
    send_signal_tid_code(tid, sig, SI_USER);
}

pub fn send_signal_tid_kernel(tid: usize, sig: usize) {
    send_signal_tid_code(tid, sig, SI_KERNEL);
}

pub fn send_sigpipe_current() {
    let tid = current_signal_id();
    send_signal_tid_code(tid, SIGPIPE, SI_KERNEL);
}

fn send_process_signal_code(pid: usize, sig: usize, code: i32) {
    if let Some(bit) = signal_bit(sig) {
        with_state_mut(pid, |state| {
            state.pending |= bit;
            state.pending_code[sig] = code;
        });
        ACTIVE_PENDING_SIGNALS.store(1, Ordering::Release);
    }

    let tids = task::process_table().thread_ids(pid);
    for tid in tids.iter().copied() {
        let _ = task::sched_wake_tid(tid);
    }
    let _ = task::futex_wake_all();
}

fn send_signal_tid_code(tid: usize, sig: usize, code: i32) {
    if let Some(bit) = signal_bit(sig) {
        with_state_mut(tid, |state| {
            state.pending |= bit;
            state.pending_code[sig] = code;
        });
        ACTIVE_PENDING_SIGNALS.store(1, Ordering::Release);
    }
    let _ = task::sched_wake_tid(tid);
    let _ = task::futex_wake_all();
}

#[inline(never)]
pub fn sys_tkill(tid: usize, sig: usize) -> isize {
    if sig >= MAX_SIGNALS {
        return EINVAL;
    }
    if !thread_exists(tid) {
        return crate::ESRCH;
    }
    if sig == 0 {
        return 0;
    }
    send_signal_tid_code(tid, sig, SI_TKILL);
    0
}

#[inline(never)]
pub fn sys_tgkill(tgid: usize, tid: usize, sig: usize) -> isize {
    if tgid == 0 || tid == 0 || sig >= MAX_SIGNALS {
        return EINVAL;
    }
    let valid = task::process_table()
        .get(tgid)
        .map(|proc| proc.threads.contains_key(&tid))
        .unwrap_or(false);
    if !valid {
        return crate::ESRCH;
    }
    if sig == 0 {
        return 0;
    }
    send_signal_tid_code(tid, sig, SI_TKILL);
    0
}

//! Minimal Flattened Device Tree (FDT / DTB) parser.
//!
//! Adapted from the migrated `kernel-rv/dtb.rs` reference. Parses the FDT
//! structure block to discover `virtio_mmio` nodes and extract their MMIO
//! base addresses.
//!
//! Also supports persistence of the DTB across soft-resets by saving a copy
//! of the DTB content in the `.data` section.

use alloc::vec::Vec;
use crate::bus::BusInfo;

// ── DTB persistence across soft-resets ────────────────────────────────

/// Maximum size of a saved DTB copy (16 KB — enough for QEMU virt).
const DTB_COPY_MAX: usize = 0x4000;

/// Last valid DTB address, saved in `.data` to survive BSS clearing.
#[link_section = ".data"]
static mut LAST_DTB_ADDR: usize = 0;

/// Static buffer holding a copy of the DTB content, in `.data`.
#[link_section = ".data"]
static mut DTB_COPY_BUF: [u8; DTB_COPY_MAX] = [0; DTB_COPY_MAX];

/// Valid size of the copy in [`DTB_COPY_BUF`], or 0 if none.
#[link_section = ".data"]
static mut DTB_COPY_SIZE: usize = 0;

/// Save the DTB address and copy its contents.
///
/// Should be called as early as possible in the kernel entry, before memory
/// allocators may overwrite the original DTB region.
pub fn save_dtb_addr(addr: usize) {
    if addr != 0 {
        unsafe { LAST_DTB_ADDR = addr; }
        save_dtb_content(addr);
    }
}

fn save_dtb_content(addr: usize) {
    let magic = unsafe { be_u32_at(addr) };
    if magic != FDT_MAGIC {
        return;
    }
    let totalsize = unsafe { be_u32_at(addr + 0x04) } as usize;
    if totalsize > DTB_COPY_MAX || totalsize < 40 {
        return;
    }
    let src = unsafe { core::slice::from_raw_parts(addr as *const u8, totalsize) };
    unsafe {
        DTB_COPY_BUF[..totalsize].copy_from_slice(src);
        DTB_COPY_SIZE = totalsize;
    }
}

// ── FDT constants ─────────────────────────────────────────────────────

const FDT_MAGIC: u32 = 0xd00dfeed;

const FDT_BEGIN_NODE: u32 = 0x0000_0001;
const FDT_END_NODE: u32   = 0x0000_0002;
const FDT_PROP: u32       = 0x0000_0003;
const FDT_END: u32        = 0x0000_0009;

const MAX_VIRTIO_DEV: usize = 8;

// ── Big-endian helpers ────────────────────────────────────────────────

fn be_u32(data: &[u8], off: usize) -> u32 {
    u32::from_be_bytes([data[off], data[off + 1], data[off + 2], data[off + 3]])
}

fn be_u64(data: &[u8], off: usize) -> u64 {
    let hi = be_u32(data, off) as u64;
    let lo = be_u32(data, off + 4) as u64;
    (hi << 32) | lo
}

unsafe fn be_u32_at(addr: usize) -> u32 {
    u32::from_be_bytes(*(addr as *const [u8; 4]))
}

fn prop_name(strings: &[u8], nameoff: usize) -> &[u8] {
    let mut end = nameoff;
    while end < strings.len() && strings[end] != 0 {
        end += 1;
    }
    &strings[nameoff..end]
}

// ── Public API ────────────────────────────────────────────────────────

/// Discover devices from a DTB at `dtb_addr`.
///
/// Returns a [`Vec`] of [`BusInfo`] entries, one per discovered device.
/// If `dtb_addr` is 0, attempts to use a previously saved DTB copy or
/// address from `.data`.
pub fn discover_devices(dtb_addr: usize) -> Vec<BusInfo> {
    let mut result: [Option<BusInfo>; MAX_VIRTIO_DEV] = [const { None }; MAX_VIRTIO_DEV];
    let mut count: usize = 0;

    if dtb_addr != 0 {
        scan_dtb_raw(dtb_addr, &mut result, &mut count);
        return result.into_iter().take(count).flatten().collect();
    }

    // Soft-reset recovery path: use saved copy.
    let copy_sz = unsafe { DTB_COPY_SIZE };
    if copy_sz > 0 {
        let all = unsafe { &DTB_COPY_BUF[..copy_sz] };
        scan_dtb_slice(all, &mut result, &mut count);
        return result.into_iter().take(count).flatten().collect();
    }

    // Fall back to saved address.
    let saved = unsafe { LAST_DTB_ADDR };
    if saved != 0 {
        scan_dtb_raw(saved, &mut result, &mut count);
        return result.into_iter().take(count).flatten().collect();
    }

    Vec::new()
}

// ── Scanning from raw address ─────────────────────────────────────────

fn scan_dtb_raw(
    dtb_addr: usize,
    result: &mut [Option<BusInfo>; MAX_VIRTIO_DEV],
    count: &mut usize,
) {
    let magic: u32;
    let totalsize: u32;
    let off_struct: u32;
    let off_strings: u32;
    let version: u32;
    let size_struct: u32;
    unsafe {
        magic       = be_u32_at(dtb_addr);
        totalsize   = be_u32_at(dtb_addr + 0x04);
        off_struct  = be_u32_at(dtb_addr + 0x08);
        off_strings = be_u32_at(dtb_addr + 0x0c);
        version     = be_u32_at(dtb_addr + 0x14);
        size_struct = be_u32_at(dtb_addr + 0x24);
    }

    if magic != FDT_MAGIC || version < 16 {
        return;
    }
    let total = totalsize as usize;
    if total > 0x200000 || total < 40 {
        return;
    }

    let all = unsafe { core::slice::from_raw_parts(dtb_addr as *const u8, total) };
    scan_dtb_slice_inner(all, off_struct as usize, off_strings as usize, size_struct as usize, result, count);
}

// ── Scanning from byte slice ──────────────────────────────────────────

fn scan_dtb_slice(
    all: &[u8],
    result: &mut [Option<BusInfo>; MAX_VIRTIO_DEV],
    count: &mut usize,
) {
    if all.len() < 40 {
        return;
    }
    let magic       = be_u32(all, 0x00);
    let off_struct  = be_u32(all, 0x08) as usize;
    let off_strings = be_u32(all, 0x0c) as usize;
    let version     = be_u32(all, 0x14);
    let size_struct = be_u32(all, 0x24) as usize;

    if magic != FDT_MAGIC || version < 16 {
        return;
    }
    if off_struct + size_struct > all.len() || off_strings > all.len() {
        return;
    }

    scan_dtb_slice_inner(all, off_struct, off_strings, size_struct, result, count);
}

