// Build script: embeds user test binaries into kernel via .incbin.
//
// Reads TEST_BIN_DIR environment variable (or defaults to scanning
// user/build/<target-arch>/ and test_bins/ relative to the workspace root).
// Generates:
//   1. link_apps.S  -- assembly with .incbin directives
//   2. apps_data.rs -- Rust module exposing APP_COUNT, APP_NAMES, get_app_data()
//
// The generated link_apps.S uses `#` style comments (GNU as), never `//`.

use std::env;
use std::fs;
use std::path::{Path, PathBuf};

fn main() {
    let out_dir = PathBuf::from(env::var("OUT_DIR").unwrap());

    // Determine the search directories for test binaries
    let mut search_dirs: Vec<PathBuf> = Vec::new();

    // 1. Honoured environment variable. When set, use it as the explicit
    // app image directory and do not scan fallback trees.
    if let Ok(dir) = env::var("TEST_BIN_DIR") {
        let path = PathBuf::from(dir);
        if path.is_absolute() {
            search_dirs.push(path);
        } else {
            let manifest_dir = PathBuf::from(env::var("CARGO_MANIFEST_DIR").unwrap());
            let workspace_root = find_workspace_root(&manifest_dir);
            search_dirs.push(workspace_root.join(path));
        }
    } else {
        // 2. Default paths relative to workspace root
        let manifest_dir = PathBuf::from(env::var("CARGO_MANIFEST_DIR").unwrap());
        // Try kernel/test_bins/
        search_dirs.push(manifest_dir.join("test_bins"));
        // Try <workspace>/user/build/<target-arch> and test_bins/.
        // Keep fallback app discovery target-scoped so concurrent RISC-V and
        // LoongArch builds never embed each other's user binaries.
        let workspace_root = find_workspace_root(&manifest_dir);
        if let Some(arch_dir) = user_build_arch_dir() {
            search_dirs.push(workspace_root.join("user").join("build").join(arch_dir));
        }
        search_dirs.push(workspace_root.join("test_bins"));
    }

    // Collect every ELF / binary we can find
    let mut apps: Vec<(String, PathBuf)> = Vec::new();

    for dir in &search_dirs {
        if !dir.exists() {
            continue;
        }
        collect_binaries(dir, &mut apps);
        // rerun if anything in these directories changes
        println!("cargo:rerun-if-changed={}", dir.display());
    }

    // If no binaries found, produce a zero-count stub so linking succeeds
    if apps.is_empty() {
        eprintln!("[build.rs] WARNING: no test binaries found; embedding empty app list");
    }

    // Sort for deterministic output
    apps.sort_by(|a, b| a.0.cmp(&b.0));

    // -- Generate link_apps.S --
    let asm = generate_link_apps_s(&apps);
    let asm_path = out_dir.join("link_apps.S");
    fs::write(&asm_path, asm).unwrap();

    // -- Generate apps_data.rs --
    let rust = generate_apps_data_rs(&apps);
    let rust_path = out_dir.join("apps_data.rs");
    fs::write(&rust_path, rust).unwrap();

    // Rerun if the build script itself changes
    println!("cargo:rerun-if-changed=build.rs");
    println!("cargo:rerun-if-env-changed=TEST_BIN_DIR");
    println!("cargo:rerun-if-env-changed=CARGO_CFG_TARGET_ARCH");
}

fn find_workspace_root(manifest_dir: &Path) -> PathBuf {
    // Walk up from crates/kernel/ to workspace root
    let mut p = manifest_dir.to_path_buf();
    while let Some(parent) = p.parent() {
        if parent.join("Cargo.toml").exists() {
            return parent.to_path_buf();
        }
        p = parent.to_path_buf();
    }
    manifest_dir.to_path_buf()
}

fn user_build_arch_dir() -> Option<&'static str> {
    match env::var("CARGO_CFG_TARGET_ARCH").ok()?.as_str() {
        "riscv64" => Some("riscv64"),
        "loongarch64" => Some("loongarch64"),
        _ => None,
    }
}

fn collect_binaries(dir: &Path, out: &mut Vec<(String, PathBuf)>) {
    if !dir.is_dir() {
        return;
    }
    if let Ok(entries) = fs::read_dir(dir) {
        for entry in entries.flatten() {
            let path = entry.path();
            let sz = path.metadata().map(|m| m.len()).unwrap_or(0);
            if path.is_dir() {
                collect_binaries_from_app_dir(&path, out);
            } else if is_elf_or_binary(&path) && sz > 1024 {
                println!("cargo:rerun-if-changed={}", path.display());
                let name = path.file_stem()
                    .and_then(|s| s.to_str())
                    .unwrap_or("app")
                    .to_string();
                let label = sanitise_label(&name);
                // Dedup: skip if this label already exists
                if !out.iter().any(|(l, _)| l == &label) {
                    eprintln!("[build.rs] found: {} ({} bytes)", path.display(), sz);
                    out.push((label, path.clone()));
                }
            }
        }
    }
}

