    // Also check for bare binaries directly inside the app directory
    if let Ok(entries) = fs::read_dir(dir) {
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_file() && is_elf_or_binary(&path) {
                println!("cargo:rerun-if-changed={}", path.display());
                let dir_name = dir.file_name()
                    .and_then(|s| s.to_str())
                    .unwrap_or("app");
                out.push((sanitise_label(dir_name), path));
            }
        }
    }
}

fn is_elf_or_binary(path: &Path) -> bool {
    // Check that it is a file with no extension, or .elf / .bin extension
    let is_file = path.is_file();
    let ok_ext = path.extension().map_or(true, |ext| {
        ext == "elf" || ext == "bin" || ext == "out"
    });
    // Also exclude common non-binary files
    let name = path.file_name().and_then(|s| s.to_str()).unwrap_or("");
    let not_junk = !name.ends_with(".txt")
        && !name.ends_with(".md")
        && !name.ends_with(".rs")
        && !name.ends_with(".sh")
        && !name.starts_with('.');
    is_file && ok_ext && not_junk
}

fn sanitise_label(name: &str) -> String {
    name.replace(|c: char| !c.is_ascii_alphanumeric() && c != '_', "_")
}

