pub fn spawn_from_memory(
    data: &[u8],
    args: &[&str],
    mut space: Option<mm::AddressSpace>,
    interp_entry: Option<usize>,
    interp_base: usize,
) -> Pid {
    let ps = platform::PAGE_SIZE;

    let elf = match mm::parse_elf(data) {
        Ok(e) => e,
        Err(_) => return spawn_failed("parse ELF"),
    };

    let mut space = match space.take() {
        Some(s) => s,
        None => match mm::AddressSpace::new_user() {
            Ok(s) => s,
            Err(_) => return spawn_failed("create address space"),
        },
    };
    let token = space.token();

    for i in 0..elf.seg_count {
        let seg = &elf.segments[i];
        if mm::load_segment_to_space(&mut space, token, data, seg, 0).is_err() {
            return cleanup_failed_spawn(token, 0, "load ELF segment");
        }
    }

    let ustack = platform::USER_STACK_TOP;
    let usp = platform::USER_STACK_SIZE / ps;
    #[cfg(target_arch = "loongarch64")]
    let initial_tp: usize = 0;
    #[cfg(not(target_arch = "loongarch64"))]
    // Per the RISC-V Linux ABI, tp is initialised to 0 for statically-linked
    // executables (no interpreter).  The C library's __libc_setup_tls() handles
    // TLS allocation.  Dynamically-linked programs get a pre-allocated page so
    // the interpreter (ld.so) can bootstrap.
    let initial_tp: usize = if interp_entry.is_some() {
        let tls_va = ustack - usp * ps - ps;
        let _ = mm::map_user_alloc(&mut space, mm::VirtAddr(tls_va), mm::pte_flags::USER_RW);
        tls_va
    } else {
        0
    };
    let _ = mm::map_user_range(
        &mut space,
        mm::VirtAddr(ustack - usp * ps),
        usp * ps,
        mm::pte_flags::USER_RW,
    );

    let user_sp = match mm::setup_user_stack(token, args, &elf, interp_base) {
        Ok(sp) => sp,
        Err(_) => return cleanup_failed_spawn(token, 0, "build user stack"),
    };

    let kstack_top = match crate::scheduler::alloc_kernel_stack() {
        Some(top) => top,
        None => return cleanup_failed_spawn(token, 0, "allocate kernel stack"),
    };

    let entry = interp_entry.unwrap_or(elf.entry);
    let trap_frame_addr = trap_frame_addr(kstack_top);
    #[cfg(any(target_arch = "riscv64", target_arch = "loongarch64"))]
    if mm::map_trap_context_by_token(token, trap_frame_addr).is_err() {
        return cleanup_failed_spawn(token, kstack_top, "map trap context");
    }
    unsafe {
        init_trap_context_in_place(trap_frame_addr, entry, user_sp, initial_tp, token, kstack_top);
    }

    let pid = alloc_pid();
    let tid = pid;

    let tcb = ThreadControlBlock {
        tid,
        pid,
        flags: 0,
        trap_cx_ppn: trap_frame_addr / ps,
        kernel_stack_top: kstack_top,
        kernel_ctx: initial_kernel_context(trap_frame_addr),
        signal_mask: 0,
        waker_ctx: 0,
        entry,
        user_sp,
        tls: initial_tp,
        set_child_tid: 0,
        clear_child_tid: 0,
        robust_list_head: 0,
        robust_list_len: 0,
        sched_policy: 0,
        sched_priority: 0,
        sched_affinity_mask: 1,
    };

    let mut brk = 0;
    for i in 0..elf.seg_count {
        brk = brk.max(elf.segments[i].vaddr + elf.segments[i].memsz);
    }

    let parent_pid = current_pid();
    let tracked_parent = if parent_pid != 0 && process_table().get(parent_pid).is_some() {
        parent_pid
    } else {
        0
    };

    let mut proc = Process::new(pid, tracked_parent);
    proc.add_thread(Thread { tid, pid, tcb });
    proc.brk = mm::align_up(brk, ps);
    proc.token = token;
    proc.fd_init();
    process_table().insert(proc);
    if tracked_parent != 0 {
        process_table().add_child_to_parent(tracked_parent, pid);
    }

    memory_fence();
    pid
}

