pub mod pte_flags {
    pub const V: usize = 1 << 0;      // Valid
    pub const D: usize = 1 << 1;      // Dirty
    pub const MAT_CC: usize = 0 << 4; // Cacheable
    pub const MAT_SUC: usize = 1 << 4;
    pub const MAT_WUC: usize = 2 << 4;
    pub const PLV0: usize = 0 << 2;   // Privilege Level 0 (kernel)
    pub const PLV3: usize = 3 << 2;   // Privilege Level 3 (user)
    pub const R: usize = 1 << 8;      // Readable
    pub const W: usize = 0;           // (LA64: write through D bit)
    pub const X: usize = 1 << 10;     // Executable

    pub const KERNEL_RW: usize = V | D | R | MAT_CC | PLV0;
    pub const KERNEL_RWX: usize = V | D | R | X | MAT_CC | PLV0;
    pub const USER_R: usize = V | R | PLV3 | MAT_CC;
    pub const USER_RW: usize = V | D | R | PLV3 | MAT_CC;
    pub const USER_RX: usize = V | R | X | PLV3 | MAT_CC;
    pub const USER_RWX: usize = V | D | R | X | PLV3 | MAT_CC;
}

