        let mut pte = pte_flags::V | pte_flags::MAT_CC;
        if flags.contains(MapFlags::READ)    { pte |= pte_flags::R; }
        if flags.contains(MapFlags::WRITE)   { pte |= pte_flags::D; }
        if flags.contains(MapFlags::EXECUTE) { pte |= pte_flags::X; }
        if flags.contains(MapFlags::USER)    { pte |= pte_flags::PLV3; }
        else { pte |= pte_flags::PLV0; }
        pte
    }
