#[cfg(target_arch = "riscv64")]
fn writable_after_cow_flags(flags: usize) -> usize {
    (flags & !pte_flags::COW) | pte_flags::W | pte_flags::V
}

#[cfg(target_arch = "loongarch64")]
fn writable_after_cow_flags(flags: usize) -> usize {
