/// Handle a page fault on `va`.  Returns `Ok(())` if resolved (CoW broken),
/// or `Err(PageFault)` if the access is truly illegal.
pub fn handle_page_fault(token: usize, va: VirtAddr, is_store: bool) -> KernelResult<()> {
    if !is_store {
        return Err(KernelError::PageFault);
    }

    let root = crate::token_root_ppn(token);
    let table = page_table::PageTable::new(root);

    // Look up the PTE
    let (pte, _level) = match table.find_pte_with_level(va) {
        Ok(p) => p,
        Err(_) => return Err(KernelError::PageFault),
    };

    // Check if this is a CoW page
    if pte.0 & pte_flags::COW == 0 {
        return Err(KernelError::PageFault);
    }

    let old_ppn = pte.ppn();
    let page_va = VirtAddr(align_down(va.0, PAGE_SIZE));

    let old_flags = page_table::raw_flags(pte.0);
    let new_flags = writable_after_cow_flags(old_flags);

    // If every other sharer has gone away, just restore write permission.
    if page_refcount(old_ppn) <= 1 {
        let mut table = page_table::PageTable::new(root);
        table.map(page_va, old_ppn, new_flags)?;
        arch_flush_tlb();
        return Ok(());
    }

    // Allocate a new physical page
    let new_page = alloc_page()?;

    // Copy old page data to new page
    unsafe {
        crate::copy_bytes_exact(
            crate::phys_to_virt(old_ppn.0 * PAGE_SIZE) as *const u8,
            crate::phys_to_virt(new_page.0 * PAGE_SIZE) as *mut u8,
            PAGE_SIZE,
        );
    }

    // Unmap the old CoW PTE, then map the new page
    let mut table = page_table::PageTable::new(root);
    table.unmap(page_va)?;
    table.map(page_va, new_page, new_flags)?;
    dec_page_ref(old_ppn);

    arch_flush_tlb();
    Ok(())
}

