                }

                let child_flags = cow_flags.unwrap_or(flags);

                if new_table
                    .map_without_flush(va, PhysPageNum(data_ppn), child_flags)
                    .is_err()
                {
                    dec_page_ref(PhysPageNum(data_ppn));
                    return Err(KernelError::NoMemory);
                }

                if let Some(parent_flags) = cow_flags {
                    old_ptes[pte_idx] = page_table::make_leaf(data_ppn, parent_flags);
                }
            }
        }
    }

    arch_flush_tlb();
    Ok(())
}

/// Update the protection flags of an existing user page by raw token.
pub fn protect_user_by_token(token: usize, va: VirtAddr, flags: usize) -> KernelResult<()> {
    if va.0 % PAGE_SIZE != 0 {
        return Err(KernelError::Invalid);
    }
    let root = token_root_ppn(token);
    let mut table = page_table::PageTable::new(root);
    let pa = translate(token, va)?;
    table.map(va, PhysPageNum(pa.0 / PAGE_SIZE), flags)
}

/// Unmap a single user page by raw token.
pub fn unmap_user_by_token(token: usize, va: VirtAddr) -> KernelResult<()> {
    if va.0 % PAGE_SIZE != 0 {
        return Err(KernelError::Invalid);
    }
    let root = token_root_ppn(token);
    let mut table = page_table::PageTable::new(root);
    table.unmap(va)
}

