/// Writable private pages are mapped read-only in both parent and child with
/// the software COW bit set. Shared-memory ranges stay shared and writable.
#[cfg(target_arch = "riscv64")]
fn cow_page_flags(flags: usize) -> Option<usize> {
    (flags & (pte_flags::W | pte_flags::COW) != 0)
        .then_some((flags & !pte_flags::W) | pte_flags::COW)
}

#[cfg(target_arch = "loongarch64")]
fn cow_page_flags(flags: usize) -> Option<usize> {
    // LoongArch reports writes to a clean page as ECODE_PME. Clearing D is the
    // architectural write-protect operation used to break COW lazily.
    (flags & (pte_flags::W | pte_flags::COW) != 0)
        .then_some((flags & !(pte_flags::W | pte_flags::D)) | pte_flags::COW)
}
